## Overview
Implement the core sync engine that pulls sessions from remote sources
using rsync over SSH for efficient delta transfer, with SFTP fallback.

## IMPORTANT SAFETY RULE
**NEVER use rsync `--delete` by default** - this could accidentally delete
local data if the remote is misconfigured or temporarily empty.

## Implementation Details

### Sync Engine Structure
Create `src/sources/sync.rs`:
```rust
pub struct SyncEngine {
    config: SourcesConfig,
    local_store: PathBuf,  // ~/.local/share/cass/remotes/
}

pub enum SyncMethod {
    Rsync,  // Preferred when available
    Sftp,   // Fallback for Windows or when rsync unavailable
}

impl SyncEngine {
    pub fn new(config: SourcesConfig) -> Self {
        let local_store = dirs::data_local_dir()
            .unwrap_or_else(|| PathBuf::from("~/.local/share"))
            .join("cass/remotes");
        Self { config, local_store }
    }

    /// Detect available sync method
    fn detect_sync_method() -> SyncMethod {
        if Command::new("rsync").arg("--version").output().is_ok() {
            SyncMethod::Rsync
        } else {
            SyncMethod::Sftp
        }
    }

    async fn sync_path_rsync(
        &self,
        source: &SourceDefinition,
        remote_path: &str,
        dest_dir: &Path,
    ) -> Result<PathSyncResult, SyncError> {
        let host = source.host.as_ref().ok_or(SyncError::NoHost)?;
        let remote_spec = format!("{}:{}", host, remote_path);
        let local_path = dest_dir.join(path_to_safe_dirname(remote_path));

        // NOTE: NO --delete flag! Safe additive sync only.
        let output = Command::new("rsync")
            .args([
                "-avz",           // Archive, verbose, compress
                "--stats",        // Show transfer stats
                "--timeout=30",   // Connection timeout
                "-e", "ssh -o BatchMode=yes -o ConnectTimeout=10",
                &remote_spec,
                local_path.to_str().unwrap(),
            ])
            .output()
            .await?;

        if !output.status.success() {
            return Err(SyncError::RsyncFailed(
                String::from_utf8_lossy(&output.stderr).to_string()
            ));
        }

        let stats = parse_rsync_stats(&String::from_utf8_lossy(&output.stdout));
        Ok(PathSyncResult {
            files_transferred: stats.files_transferred,
            bytes_transferred: stats.bytes_transferred,
        })
    }

    async fn sync_path_sftp(
        &self,
        source: &SourceDefinition,
        remote_path: &str,
        dest_dir: &Path,
    ) -> Result<PathSyncResult, SyncError> {
